import java.sql.*;

public class FinancialTransactionProcessor {
    public void processTransaction(String accountNumber, double transactionAmount) throws SQLException {
        Connection conn = null;
        Statement stmt = null;
        ResultSet rs = null;
        try {
            // Get the current balance of the account from the database
            conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/bank", "username", "password");
            stmt = conn.createStatement();
            String sql = "SELECT balance FROM accounts WHERE account_number = ?";
            rs = stmt.executeQuery(sql, new Object[] {accountNumber});
            
            // Check if the transaction amount is valid and the account has sufficient balance
            double currentBalance = 0;
            while (rs.next()) {
                currentBalance = rs.getDouble("balance");
                if (currentBalance - transactionAmount < 0) {
                    throw new SQLException("Insufficient balance for the transaction");
                }
            }
            
            // Update the account balance in the database
            sql = "UPDATE accounts SET balance = ? WHERE account_number = ?";
            stmt.executeUpdate(sql, new Object[] {currentBalance - transactionAmount, accountNumber});
        } finally {
            if (rs != null) {
                rs.close();
            }
            if (stmt != null) {
                stmt.close();
            }
            if (conn != null) {
                conn.close();
            }
        }
    }
}